package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Method;

public class CSVFormatTest {

    @Test
    public void testWithTrim_DefaultTrue() {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat trimmedFormat = format.withTrim();
        assertNotNull(trimmedFormat);
        assertTrue(trimmedFormat.getTrim());
        // Original format should remain unchanged
        assertFalse(format.getTrim());
    }

    @Test
    public void testWithTrim_False() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        Method method = CSVFormat.class.getDeclaredMethod("withTrim", boolean.class);
        method.setAccessible(true);
        CSVFormat trimmedFalseFormat = (CSVFormat) method.invoke(format, false);
        assertNotNull(trimmedFalseFormat);
        assertFalse(trimmedFalseFormat.getTrim());
        // Original format should remain unchanged
        assertFalse(format.getTrim());
    }

    @Test
    public void testWithTrim_True() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT;
        Method method = CSVFormat.class.getDeclaredMethod("withTrim", boolean.class);
        method.setAccessible(true);
        CSVFormat trimmedTrueFormat = (CSVFormat) method.invoke(format, true);
        assertNotNull(trimmedTrueFormat);
        assertTrue(trimmedTrueFormat.getTrim());
        assertFalse(format.getTrim());
    }
}
